// Calcola il range del mese precedente
const now = new Date();
const year = now.getMonth() === 0 ? now.getFullYear() - 1 : now.getFullYear();
const month = now.getMonth() === 0 ? 12 : now.getMonth(); // 1-12

const startDate = `${year}-${String(month).padStart(2,'0')}-01`;
// Ultimo giorno del mese
const lastDay = new Date(year, month, 0).getDate();
const endDate = `${year}-${String(month).padStart(2,'0')}-${String(lastDay).padStart(2,'0')}`;

const mesi = ['Gennaio','Febbraio','Marzo','Aprile','Maggio','Giugno','Luglio','Agosto','Settembre','Ottobre','Novembre','Dicembre'];
const nomeMese = mesi[month - 1];
const fileName = `Pagamenti_${nomeMese}_${year}.csv`;

return [{ json: { startDate, endDate, year, month, nomeMese, fileName } }];

// Costruisce il CSV dei pagamenti del mese con totali
const meta = $('Calcola Mese Precedente').item.json;
const sedute = $input.first().json;
const fileName = meta.fileName;

if (!Array.isArray(sedute) || sedute.length === 0) {
  const bom = '\uFEFF';
  const header = 'Data;Cognome;Nome;C.F.;Indirizzo;Tipo Pagamento;Importo;Metodo';
  const totals = '\n\n--- RIEPILOGO ---\nTotale Contanti;€0\nTotale POS;€0\nTotale Online (PayPal);€0\nTOTALE GENERALE;€0';
  return [{ json: { fileName, csv: bom + header + totals, isEmpty: true } }];
}

const fmtDate = iso => {
  if (!iso) return '';
  const d = new Date(iso);
  return String(d.getDate()).padStart(2,'0') + '/' + String(d.getMonth()+1).padStart(2,'0') + '/' + d.getFullYear();
};
const fmtEur = n => n != null ? Number(n).toFixed(2).replace('.', ',') : '0,00';
const fmtMetodo = m => m === 'contanti' ? 'Contanti' : m === 'pos' ? 'POS' : (m === 'paypal' || m) ? 'Online (PayPal)' : '';

let totContanti = 0;
let totPOS = 0;
let totOnline = 0;
const rows = [];

for (const s of sedute) {
  const c = s.clients || {};
  const nome = c.first_name || '';
  const cognome = c.last_name || '';
  const cf = c.codice_fiscale || '';
  const indirizzo = c.indirizzo || '';
  const accPaid = s.amount_paid != null ? Number(s.amount_paid) : 0;
  const price = s.session_price != null ? Number(s.session_price) : 0;

  // Riga acconto
  if (accPaid > 0) {
    // Fallback paypal: prenotazioni dal sito usano sempre PayPal
    const accMetodo = s.acconto_payment_method || 'paypal';
    rows.push([fmtDate(s.created_at || s.scheduled_at), cognome, nome, cf, indirizzo, 'Acconto', fmtEur(accPaid), fmtMetodo(accMetodo)].join(';'));
    if (accMetodo === 'contanti') totContanti += accPaid;
    else if (accMetodo === 'pos') totPOS += accPaid;
    else totOnline += accPaid;
  }

  // Riga saldo
  if (price > 0) {
    const saldo = Math.max(0, price - accPaid);
    if (saldo > 0) {
      const salMetodo = s.session_payment_method || '';
      rows.push([fmtDate(s.scheduled_at), cognome, nome, cf, indirizzo, 'Saldo seduta', fmtEur(saldo), fmtMetodo(salMetodo)].join(';'));
      if (salMetodo === 'contanti') totContanti += saldo;
      else if (salMetodo === 'pos') totPOS += saldo;
      else if (salMetodo) totOnline += saldo;
    }
  }
}

const totale = totContanti + totPOS + totOnline;

const bom = '\uFEFF';
const header = 'Data;Cognome;Nome;C.F.;Indirizzo;Tipo Pagamento;Importo;Metodo';
const summary = [
  '',
  '',
  '--- RIEPILOGO ' + meta.nomeMese.toUpperCase() + ' ' + meta.year + ' ---',
  'Totale Contanti;€' + fmtEur(totContanti),
  'Totale POS;€' + fmtEur(totPOS),
  'Totale Online (PayPal);€' + fmtEur(totOnline),
  'TOTALE GENERALE;€' + fmtEur(totale),
  '',
  'Numero sedute;' + sedute.length,
].join('\n');

const csv = bom + header + '\n' + rows.join('\n') + summary;

return [{ json: { fileName, csv, isEmpty: false, totContanti, totPOS, totOnline, totale, numSedute: sedute.length } }];

// Converti il CSV in file binario per upload su Drive
const { fileName, csv } = $input.first().json;
const buffer = Buffer.from(csv, 'utf-8');
return [{
  json: { fileName },
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'text/csv',
      fileName: fileName,
    }
  }
}];

// Passa l'ID della cartella creata e i dati CSV dal nodo precedente
const folderId = $input.first().json.id;
const csvData = $('Converti in File').item;
return [{ json: { ...csvData.json, folderId }, binary: csvData.binary }];
